  ('1ac3aac4-477d-43be-8b69-9b3786b91e8f'::uuid, '2bb06e17-6c38-4c32-a845-90bbb733f61e'::uuid, null, 'product_updated', 'codex_blackmores_clean_approval', '{"id":"2bb06e17-6c38-4c32-a845-90bbb733f61e","title":"Blackmores Run Down Rescue","region":"TH","source":"manufacturer_import","status":"pending_review","brand_id":"40e4806a-5049-4668-8d29-ab36a31202dd","category":null,"currency":"THB","platform":"manual","title_en":"Blackmores Run Down Rescue","title_th":null,"image_url":"https://images.contentstack.io/v3/assets/blt948bd74310fc0ad0/blt1e655a0f3ce73ed0/68bfbc885fb6b7354fe3dffe/93564281-1.webp","brand_name":"blackmores","created_at":"2026-05-21T13:09:48.272611+00:00","source_url":"https://www.blackmores.com.au/products/run-down-rescue","updated_at":"2026-05-21T13:09:48.287084+00:00","admin_notes":null,"description":"Blackmores Run Down Rescue supports immune system and helps relieve fatigue and tiredness.","product_url":"https://www.blackmores.com.au/products/run-down-rescue","label_status":"parsed","price_amount":null,"product_kind":"supplement","description_en":"Blackmores Run Down Rescue supports immune system and helps relieve fatigue and tiredness.","description_th":null,"normalized_url":"https://www.blackmores.com.au/products/run-down-rescue","current_version":1,"fda_verified_at":null,"price_cached_at":null,"source_snapshot":{"dosage":"for use. Read the","locale":"en","parser":"blackmores_structured_ingredients_v2","titleEn":"Blackmores Run Down Rescue","htmlLength":169778,"validation":{"status":"pass","reasons":[],"summary":"5 matchable canonical facts.","checkedAt":"2026-05-21T13:09:48.284Z","matchableFactCount":5},"description":"Blackmores Run Down Rescue supports immune system and helps relieve fatigue and tiredness.","descriptionEn":"Blackmores Run Down Rescue supports immune system and helps relieve fatigue and tiredness.","descriptionTh":null,"extractedText":"Blackmores Run Down Rescue – immune & energy support All Products Shop All Products New Products Best Sellers Vegan Certified Women&#x27;s Health Men&#x27;s Health Kid&#x27;s Health Infant & Toddler Nutrition By Category Arthritis, Joint & Bone Brain & Cognitive Health Cold, Flu & Immunity Digestive & Gut Health Energy Everyday Health Eye Health Fish & Nutritional Oils Heart Health Infant & Toddler Nutrition Kids&#x27; Health Men&#x27;s Health Multivitamins Muscle Support Nails, Hair & Skin Preconception, Pregnancy & Breastfeeding Stress Relief & Sleep Support Women&#x27;s Health By Ingredient Calcium CoQ10 Curcumin Echinacea Fish Oil & Omega 3 Glucosamine Iron Magnesium Probiotics Selenium Vitamin B Vitamin C Vitamin D Vitamin E Zinc Health Hub By Categories By Type Latest Articles Action Plans Arthritis, Bone & Joint Beauty & Skincare Brain & Cognitive Health Cold, Flu & Immunity Digestive & Gut Health Energy Everyday Health Eye Health Fish & Nutrition Oils Heart & Cardiovascular Health Kids & Infant Health Men&#x27;s Health Muscle Support & Fitness Preconception, Pregnancy & Breastfeeding Recipes Stress Relief & Sleep Support Women&#x27;s Health Action Plans Articles Recipes Latest Articles About Blackmores About Blackmores Our Heritage Our Approach Our Impact Our Sustainability Pillars Our People & Culture Our Careers Our Ambassadors & Partners Contact us Ask A Naturopath Our Newsroom Blackmores Subscribe Search Home Chevron Icon Horizontal products Chevron Icon Horizontal Blackmores Run Down Rescue Size Size 30 tablets Blackmores Run Down Rescue combines Siberian ginseng, vitamin C, reishi mushroom, astragalus, selenium and zinc to help relieve tiredness and feelings of weakness, support energy levels, immune system health, and reduce free radical damage to body cells. A multi‑action formula to support general health and wellbeing - because good health changes everything. Product Format Tablet Always read the label and follow the directions for use. Read the warnings before purchase. Support For Immune System Health Energy Halal Certified No Added Yeast No Added Gluten No Added Wheat No Added Dairy No Added Soya Bean Benefits & How To Use Benefits An advanced formula with vitamin C, zinc, selenium and betacarotene plus astragalus, echinacea, ginseng and reishi mushroom extract. Relieves tiredness and feelings of weakness. Supports energy levels. Supports immune system health. Supports general health & wellbeing. Dosage Adults When feeling run down: Take 2 tablets once a day. Take with food. Warnings Always read the label and follow the directions for use. Do not use during pregnancy or breastfeeding. WARNING: Contains zinc which may be dangerous if taken in large amounts or for a long period. This product contains selenium which is toxic in high doses. A daily dose of 150 micrograms for adults of selenium from dietary supplements should not be exceeded. If symptoms persist talk to your health professional. Dietary supplements can only be of assistance if dietary intake is inadequate. Adults only. If you have any pre-existing conditions or are on any medications always talk to your health professional before use. Some products should be ceased at least two weeks before any elective surgery, please confirm with your health professional. Contains fish and sulfites. Benefits Dosage Warnings An advanced formula with vitamin C, zinc, selenium and betacarotene plus astragalus, echinacea, ginseng and reishi mushroom extract. Relieves tiredness and feelings of weakness. Supports energy levels. Supports immune system health. Supports general health & wellbeing. Adults When feeling run down: Take 2 tablets once a day. Take with food. Always read the label and follow the directions for use. Do not use during pregnancy or breastfeeding. WARNING: Contains zinc which may be dangerous if taken in large amounts or for a long period. This product contains selenium which is toxic in high doses. A daily dose of 150 micrograms for adults of selenium from dietary supplements should not be exceeded. If symptoms persist talk to your health professional. Dietary supplements can only be of assistance if dietary intake is inadequate. Adults only. If you have any pre-existing conditions or are on any medications always talk to your health professional before use. Some products should be ceased at least two weeks before any elective surgery, please confirm with your health professional. Contains fish and sulfites. The Blackmores Difference Ingredients Active ingredients per tablet: Astragalus membranaceus (astragalus) extract dry conc. 200 mg equivalent dry root 3000 mg (3 g) Ganoderma lucidum (reishi mushroom) extract dry conc. 37.5 mg equivalent dry fruiting body 750 mg Echinacea purpurea (echinacea) extract dry conc. 125 mg equivalent dry root 750 mg Eleutherococcus senticosus (Siberian ginseng) extract dry conc. 66.7 mg equivalent dry root 1000 mg (1 g) Ascorbic acid (vitamin C) 250 mg Zinc amino acid chelate 75 mg equivalent zinc 15 mg Betacarotene 720 micrograms Selenomethionine 124 micrograms equivalent selenium 50 micrograms Show More Run Down Rescue Reviews Let&#x27;s stay in touch Instagram Facebook TikTok LinkedIn Back To Top About Blackmores About Blackmores Our Heritage Our Approach Our Impact Our Sustainability Approach Our People & Culture Our Careers Our Ambassadors & Partners Our Newsroom About Blackmores About Blackmores Our Heritage Our Approach Our Impact Our Sustainability Approach Our People & Culture Our Careers Our Ambassadors & Partners Our Newsroom Our Brands & Products Shop Our Products Shop Best Sellers BioCeuticals Blackmores Professional Blackmores Institute Blackmores Education Our Brands & Products Shop Our Products Shop Best Sellers BioCeuticals Blackmores Professional Blackmores Institute Blackmores Education International Markets China Hong Kong SAR iHerb Indonesia Korea Malaysia New Zealand Singapore Taiwan Region Thailand Vietnam International Markets China Hong Kong SAR iHerb Indonesia Korea Malaysia New Zealand Singapore Taiwan Region Thailand Vietnam Terms & Poli