  ('268205e8-0007-4ed6-9df5-c7cd3fd93e3e'::uuid, 'b1fda282-2d4d-4b90-92a3-bafbef1e68b4'::uuid, null, 'product_updated', 'codex_blackmores_clean_approval', '{"id":"b1fda282-2d4d-4b90-92a3-bafbef1e68b4","title":"Blackmores Toddler Milk Drink","region":"TH","source":"manufacturer_import","status":"pending_review","brand_id":"40e4806a-5049-4668-8d29-ab36a31202dd","category":null,"currency":"THB","platform":"manual","title_en":"Blackmores Toddler Milk Drink","title_th":null,"image_url":"https://images.contentstack.io/v3/assets/blt948bd74310fc0ad0/bltc56e3f7acc8a4666/68bfbb40ac205ea528bcfca4/9300807358269-1.webp","brand_name":"blackmores","created_at":"2026-05-21T13:09:48.752256+00:00","source_url":"https://www.blackmores.com.au/products/toddler-milk-drink","updated_at":"2026-05-21T13:09:48.766418+00:00","admin_notes":null,"description":"Blackmores® Toddler Milk Drink contains the essential vitamins and minerals to support your growing toddlers&#x27; nutritional needs.","product_url":"https://www.blackmores.com.au/products/toddler-milk-drink","label_status":"parsed","price_amount":null,"product_kind":"multi","description_en":"Blackmores® Toddler Milk Drink contains the essential vitamins and minerals to support your growing toddlers&#x27; nutritional needs.","description_th":null,"normalized_url":"https://www.blackmores.com.au/products/toddler-milk-drink","current_version":1,"fda_verified_at":null,"price_cached_at":null,"source_snapshot":{"dosage":"for use. Read the","locale":"en","parser":"blackmores_structured_ingredients_v2","titleEn":"Blackmores Toddler Milk Drink","htmlLength":239382,"validation":{"status":"pass","reasons":[],"summary":"17 matchable canonical facts.","checkedAt":"2026-05-21T13:09:48.764Z","matchableFactCount":17},"description":"Blackmores® Toddler Milk Drink contains the essential vitamins and minerals to support your growing toddlers&#x27; nutritional needs.","descriptionEn":"Blackmores® Toddler Milk Drink contains the essential vitamins and minerals to support your growing toddlers&#x27; nutritional needs.","descriptionTh":null,"extractedText":"Toddler Milk Drink | Blackmores All Products Shop All Products New Products Best Sellers Vegan Certified Women&#x27;s Health Men&#x27;s Health Kid&#x27;s Health Infant & Toddler Nutrition By Category Arthritis, Joint & Bone Brain & Cognitive Health Cold, Flu & Immunity Digestive & Gut Health Energy Everyday Health Eye Health Fish & Nutritional Oils Heart Health Infant & Toddler Nutrition Kids&#x27; Health Men&#x27;s Health Multivitamins Muscle Support Nails, Hair & Skin Preconception, Pregnancy & Breastfeeding Stress Relief & Sleep Support Women&#x27;s Health By Ingredient Calcium CoQ10 Curcumin Echinacea Fish Oil & Omega 3 Glucosamine Iron Magnesium Probiotics Selenium Vitamin B Vitamin C Vitamin D Vitamin E Zinc Health Hub By Categories By Type Latest Articles Action Plans Arthritis, Bone & Joint Beauty & Skincare Brain & Cognitive Health Cold, Flu & Immunity Digestive & Gut Health Energy Everyday Health Eye Health Fish & Nutrition Oils Heart & Cardiovascular Health Kids & Infant Health Men&#x27;s Health Muscle Support & Fitness Preconception, Pregnancy & Breastfeeding Recipes Stress Relief & Sleep Support Women&#x27;s Health Action Plans Articles Recipes Latest Articles About Blackmores About Blackmores Our Heritage Our Approach Our Impact Our Sustainability Pillars Our People & Culture Our Careers Our Ambassadors & Partners Contact us Ask A Naturopath Our Newsroom Blackmores Subscribe Search Home Chevron Icon Horizontal products Chevron Icon Horizontal Blackmores Toddler Milk Drink Size Size 900 grams Blackmores Toddler Milk Drink is made with premium Australian cow’s milk and a tailored blend of nutrients to support busy toddlers aged 12 months and over. It helps support nutritional intake during this active stage of growth, when dietary needs continue to evolve. Product Format Powder Always read the label and follow the directions for use. Read the warnings before purchase. Support For Infant & Toddler Nutrition Halal Certified Benefits & How To Use Benefits Combined with a balanced diet, Blackmores Toddler Milk Drink contains essential vitamins and minerals to support your growing toddlers&#x27; nutritional needs. Made using high quality ingredients and premium fresh Australian milk from cows in the lush pastures of Australia. Special blend of ingredients with 17 essential vitamins and minerals. Essential vitamins A, D, E and calcium to help support your toddlers&#x27; healthy growth and development. Rich in calcium and magnesium to help support strong bones and teeth With vitamin C and zinc to help support a healthy immune system function. Contains iodine and iron which contributes to support your toddler&#x27;s cognitive development. Contains lutein. No nasties - no GMO, no artificial sweeteners or flavours and has no added gluten. Warnings Always read the label and follow the directions for use. Follow instructions exactly. Prepare bottles and teats as directed. Do not change proportions of powder except on medical advice. Incorrect preparation can make your baby very ill. This product is a formulated supplementary food for young children. Should not be used for children under 12 months. CONTAINS MILK AND SOY. MAY CONTAIN FISH. Feeding Guide FEEDING GUIDE - TO PREPARE ONE FEED Age of infant Cooled boiled water (mL) Level scoops of formula Formula feeds per day 12 - 24 months 200 mL 4 2-3 One level scoop = 8.5 g of formula. HOW TO PREPARE Wash hands and all equipment before preparing Blackmores Toddler Milk Drink. Measure out the required amount of water and powder by consulting the feeding guide on the product label. Use only the scoop provided, lightly fill one measurement of the powder and use levelling blade on tin. Pour powder into the water, stir or shake until the powder is dissolved. Benefits Warnings Feeding Guide Combined with a balanced diet, Blackmores Toddler Milk Drink contains essential vitamins and minerals to support your growing toddlers&#x27; nutritional needs. Made using high quality ingredients and premium fresh Australian milk from cows in the lush pastures of Australia. Special blend of ingredients with 17 essential vitamins and minerals. Essential vitamins A, D, E and calcium to help support your toddlers&#x27; healthy growth and development. Rich in calcium and magnesium to help support strong bones and teeth With vitamin C and zinc to help support a healthy immune system function. Contains iodine and iron which contributes to support your toddler&#x27;s cognitive development. Contains lutein. No nasties - no GMO, no artificial sweeteners or flavours and has no added gluten. Always read the label and follow the directions for use. Follow instructions exactly. Prepare bottles and teats as directed. Do not change proportions of powder except on medical advice. Incorrect preparation can make your baby very ill. This product is a formulated supplementary food for young children. Should not be used for children under 12 months. CONTAINS MILK AND SOY. MAY CONTAIN FISH. FEEDING GUIDE - TO PREPARE ONE FEED Age of infant Cooled boiled water (mL) Level scoops of formula Formula feeds per day 12 - 24 months 200 mL 4 2-3 One level scoop = 8.5 g of formula. HOW TO PREPARE Wash hands and all equipment before preparing Blackmores Toddler Milk Drink. Measure out the required amount of water and powder by consulting the feeding guide on the product label. Use only the scoop provided, lightly fill one measurement of the powder and use levelling blade on tin. Pour powder into the water, stir or shake until the powder is dissolved. The Blackmores Difference Nutritional Information Servings per can: Approx. 26 Serving size: Approx. 227 mL (34 g and 200 mL water) Average quantity per 227 mL prepared Toddler Milk Drink % RDI* per serve Average quantity per 100 mL Energy 678 kJ 299 kJ Protein, total 6.00 g 2.64 g Gluten Not detected Not detected Fat, total 7.14 g 3.15 g saturated 3.54 g 1.56 g trans 0.17 g 0.07 g monounsaturated 2.55 g 1.12 g polyunsaturated 0.88 g 0.39 g Docosahexaenoic Acid (DHA) 10.2 mg 4.49 mg alpha-linolenic Acid (ALA) 68.0 mg 29.9 mg Arachidonic Acid (ARA) 10.2 mg 4.49 mg Linoleic Acid 0.68 g 0.30 g Carbohydrate 17.8 g 7.84 g sugars 14.4 g 6.34 g Dietary Fibre, total (as Galacto-oligosaccharide) 1.20 g 0.53 g Galacto-oligosaccharide (GOS) 1.20 g 0.53 g Sodium 60 mg 26.4 mg Potassium 224 mg 98.7 mg Vitamins Vitamin A 76.5 µg RE 26% 33.7 µg RE Thiamin (vitamin B1) 0.21 mg 42% 0.09 mg Riboflavin (vitamin B2) 0.34 mg 43% 0.15 mg Niacin (vitamin B3) 1.36 mg 27% 0.60mg Vitamin B6 0.21 mg 30% 0.09 mg Folate (vitamin B9) 34.0 µg 34% 15.0 µg Vitamin B12 0.50 µg 50% 0.22 µg Vitamin C 15.0 mg 50% 6.61 mg Vitamin D 1.50 µg 30% 0.66 µg Vitamin E 2.50 mg α-TE 50% 1.10 mg α-TE Minerals Calcium 221 mg 32 % 97.4 mg Iodine 20.4 µg 29% 8.99 µg Iron 2.6 mg 43% 1.15 mg Magnesium 20.4 mg 26% 8.99 mg Phosphorus 146 mg 29% 64.3 mg Zinc 1.10 mg 24% 0.48 mg Other Lutein 37.5 µg 16.5 µg # Every 28 g of fat contains 4.2 g of beta palmitate as oleic palmitic oleic (OPO). *RDI: Recommended Dietary intake for children 1-3 years (FSANZ- Food Standards Australia New Zealand) Ingredients Milk Solids, Vegetable Oil Blend# ( Soy ), Maltodextrin, Galacto-oligosaccharide (GOS) ( Milk ), Acidity Regulator (Potassium Citrate), Emulsifier ( Soy Lecithin), Arachidonic Acid (ARA) ( Milk ), Docosahexaenoic Acid (DHA) ( Milk ), Lutein, Antioxidants (Ascorbyl Palmitate, Tocopherol Concentrate, Mixed). Minerals (Magnesium Sulphate, tri Calcium Phosphate, Calcium Carbonate, Ferric Pyrophosphate, Zinc Sulphate, Potassium Iodide). Vitamins (Sodium Ascorbate (vitamin C), d-alpha Tocopheryl Acetate (vitamin E) ( Soy ), Nicotinamide (vitamin B3), Retinyl Acetate (vitamin A), Folic Acid (vitamin B9), Cyanocobalamin (vitamin B12), Pyridoxine Hydrochloride (vitamin B6), Thiamine Hydrochloride (vitamin B1), Riboflavin (vitamin B2), Cholecalciferol (vitamin D)). CONTAINS MILK AND SOY. MAY CONTAIN FISH. Frequently asked questions about Toddler Milk Drink How can I learn more about the Blackmores Infant Nutrition Range? You can learn more about the range and read our FAQs here . Alternatively, contact our Naturopathic Advisory Team on 1800 803 760 . What is Blackmores Toddler Milk Drink (Stage 3) The Toddler Milk Drink has been formulated to help meet the nutritional requirements of children aged 12 months and older. A toddler’s nutritional requirements are different from those of younger babies. It is a tasty milk drink containing iodine needed for cognitive function, zinc & vitamin C to support immunity, vitamin D and calcium for growing bones. It should not be used as the sole source of nutrition but to supplement a normal diet to address situations where intakes of energy and nutrients may not be adequate to meet an individual’s requirements. When can I start giving my child Toddler Milk Drink (Stage 3)? It is important to choose a formula that is age-appropriate. If unsure, consult your health care professional for advice but our Toddler Milk Drink has been formulated to help meet the nutritional requirements of children aged 12 months and older. Blackmores Toddler Milk Drink supports busy toddlers&#x27; nutritional needs and contains iodine which contributes to cognitive function; iron, zinc and vitamins C, A & D to support healthy immunity; vitamin D and calcium for growing bones. The Toddler Milk Drink is a supplement to a normal diet to address situations where intakes of energy and nutrients may not be adequate to meet a busy toddler’s requirements. How many feeds a day of Toddler Milk Drink (Stage 3) can I give my toddler? Blackmore’s Toddler Milk Drink is a formulated supplementary food for young children aged from 12 months of age. It can be consumed when energy and nutrient intakes may not be adequate and should be consumed as part of a diverse diet. Two to three serves a day will provide a tasty milk drink supplement to your toddler’s diet. How long can the product be used once opened? We recommend you use the contents of the tin within 4 weeks of opening. How do I prepare my baby’s formula? Please look at both methods detailed below and choose the one that is best for your family. If you are unable to reliably store your baby’s formula in cool, dry conditions, your baby has health issues or was born prematurely, please consider using the hot water preparation with water no cooler than 70°C. Preparing formula with hot water Preparing formula with cooled water Preparing formula with cooled water (Vietnamese) The WHO and other many other health advisory bodies advise that best practice is to boil the kettle and allow it to cool for just under half an hour to reach approximately 70°C. You then add the powder to the water and can cool the prepared milk down to feeding temperature quickly by running the bottle under the cold water tap or placing in a jug of cool water. Please be sure to check that the milk has cooled down to the right temperature before you feed your baby. It should feel just slightly warm on your skin. Can my baby use Blackmores Toddler Milk Drink (Stage 3) after 24 months? Yes, Toddler Milk Drink is appropriate for children over the age of 12 months who want to continue using a milk drink that is fortified with some added nutrients as part of balanced diet. There is no cut off age for using Toddler Milk drink, you can choose to continue to give it as long as you feel your child needs it. It is important to remember that Toddler Milk should not be used as the only source of nutrition, it is to be used as a supplement to the normal diet for those that need some extra nutritional support. Toddler Milk Drink Reviews Let&#x27;s stay in touch Instagram Facebook TikTok LinkedIn Back To Top About Blackmores About Blackmores Our Heritage Our Approach Our Impact Our Sustainability Approach Our People & Culture Our Careers Our Ambassadors & Partners Our Newsroom About Blackmores About Blackmores Our Heritage Our Approach Our Impact Our Sustainability Approach Our People & Cultur","productImportId":"bccee3d7-8da2-40fc-a3df-4b9b86f8f25e","aiFactCorrection":{"notes":"Cleaned garbled nutrition rows to canonical vitamins/minerals/GOS with per-serve doses from structured label data; removed fat/carbs/protein and non-catalogue items like lutein/DHA.","responseId":"139f5472-b47f-9dec-9872-ec88f2e3594b","correctedAt":"2026-05-18T17:03:45.278Z","originalFactCount":27,"correctedFactCount":17},"activeIngredientCount":27,"structuredIngredients":[],"candidateSupplierReason":"Blackmores Thailand product pages expose structured active ingredient tables, product images and FDA advertising approval text."},"affiliate_status":"none","normalized_title":"blackmores_toddler_milk_drink","product_audience":"both","validation_status":"pass","validation_reasons":[],"validation_summary":"17 matchable canonical facts.","availability_status":"unknown","external_product_id":null,"fda_approval_number":null,"affiliate_checked_at":null,"normalized_brand_name":"blackmores","validation_checked_at":"2026-05-21T13:09:48.764+00:00","availability_cached_at":null,"product_data_expires_at":null}'::jsonb, '{"status":"approved","version":2,"changeNote":"approve_clean_blackmores_validation_pass","validation":{"status":"pass","reasons":[],"summary":"17 matchable canonical facts.","checkedAt":"2026-05-21T13:10:34.217Z","matchableFactCount":17},"sourceSnapshotPatch":null,"manufacturerCountriesChanged":false}'::jsonb, '2026-05-21T13:10:34.222Z'::timestamptz),
