  ('2c93d0de-a55d-4109-b5a0-46016e1ec9be'::uuid, '9bf782e8-41dc-4a29-9bec-9934689adb34'::uuid, null, 'product_updated', 'manufacturer_scraper_auto_review', '{"id":"9bf782e8-41dc-4a29-9bec-9934689adb34","title":"DHC Daily Grain Koji and Live Enzymes 30 Days","region":"TH","source":"manufacturer_import","status":"pending_review","brand_id":"17f6ebfb-bc28-4471-84e6-12fccfd93e06","category":null,"currency":"THB","platform":"manual","title_en":"DHC Daily Grain Koji and Live Enzymes 30 Days","title_th":"ดีเอชซี เกรนโคจิและเอนไซม์สด 30 วัน","image_url":"https://www.dhc.co.jp/dw/image/v2/BLLL_PRD/on/demandware.static/-/Sites-dhc_catalog-ms/default/dw157ef9cb/large/32535/32535_G.png?sw=256&sh=256&sm=cut","brand_name":"dhc","created_at":"2026-05-21T10:14:17.315649+00:00","source_url":"https://www.dhc.co.jp/goods/32535.html","updated_at":"2026-05-21T10:14:17.329651+00:00","admin_notes":null,"description":"生きた酵素をそのまま！ 穀物9種を麹菌3種で醗酵させた“穀物麹”サプリ","product_url":"https://www.dhc.co.jp/goods/32535.html","label_status":"missing","price_amount":null,"product_kind":"supplement","description_en":"Fermented grain koji supplement with live enzymes from 9 domestic grains, yeast powder and silk.","description_th":"อาหารเสริมโคจิจากธัญพืชหมักพร้อมเอนไซม์สดจากธัญพืช 9 ชนิด ผงยีสต์และผงไหม","normalized_url":"https://www.dhc.co.jp/goods/32535.html","current_version":1,"fda_verified_at":null,"price_cached_at":null,"source_snapshot":{"locale":"ja","parser":"dhc_demandware_health_supplements_v1","titleEn":"DHC Daily Grain Koji and Live Enzymes 30 Days","titleTh":"ดีเอชซี เกรนโคจิและเอนไซม์สด 30 วัน","htmlHash":"e84f223ab333184ca9cc0aa8e7358722af5e918e95799a64ad041ccb098ff40a","nutrition":"『毎日、とりたい 穀物麹と生酵素』は伝統的な日本の醗酵食品として知られる“麹”の恵みを、ぎゅっと凝縮したサプリメントです。大麦や玄米、黒米など厳選した9種類の国産穀物を、白・黒・黄3種類の麹菌で醗酵させた“穀物麹”を使っています。健康や美容に良いとされる醗酵パワーを摂れるだけじゃなく、“穀物麹”に含まれる生きた食物酵素をそのまま摂れるのがうれしいポイント。 外食や加工食品が多いなど食生活が気になる方、加齢による栄養不足や偏りが気になる方のサポートにもおすすめです。 “穀物麹”の原料は安心の国産 穀物麹の原料は栄養バランスに優れた＜白米、大麦、玄米、赤米、あわ、ひえ、きび、たかきび、黒米＞の9種類。厳選した国産穀物のみを使用し、独自のバランスで配合しました。 3種の麹菌が幅広くはたらく！ 麹菌とはカビの一種で、醗酵食品を作るうえで欠かせないもの。味噌や醤油、日本酒など古くから日本の食卓に並ぶ食品に使用されています。『毎日、とりたい 穀物麹と生酵素』は数ある麹菌の中から、白・黒・黄色3種の麹菌を厳選しました。 白麹菌 醗酵クエン酸をつくるので酸性に強い酵素を持っています。 黒麹菌 醗酵クエン酸をつくるので酸性に強い酵素を持っています。植物性食品の細胞壁を分解して栄養素を溶出しやすくする特徴も。 黄麹菌 中性でよくはたらく酵素を持っています。 JANコード： 4511413622896 ※水またはぬるま湯で噛まずにそのままお召し上がりください。 ※本品は天然素材を使用しているため、色調に若干差が生じる場合があります。これは色の調整をしていないためであり、成分含有量や品質に問題はありません。 【名称】穀物麹加工食品 【原材料名】穀物麹（白米、大麦、玄米、赤米、あわ、ひえ、きび、たかきび、黒米）（国内製造）、乳酸菌・酵母醗酵殺菌粉末（乳成分を含む）、納豆菌末、シルク末/セルロース、微粒二酸化ケイ素、ステアリン酸Ca 【内容量】18.0g（1粒重量300mg×60粒） 【栄養成分表示】［1日あたり：2粒600mg］熱量2.2kcal、たんぱく質0.09g、脂質0.007g、炭水化物0.45g、食塩相当量0.001g、穀物麹350mg、乳酸菌・酵母醗酵殺菌粉末100mg（乳酸菌4種＋酵母菌3種）、納豆菌末30mg、シルク末30mg アレルギー物質 乳 健康食品について ※一日摂取目安量を守って、お召し上がりください。 ※お身体に異常を感じた場合は、摂取を中止してください。 ※特定原材料及びそれに準ずるアレルギー物質を対象範囲として表示しています。原材料をご確認の上、食物アレルギーのある方はお召し上がりにならないでください。 ※薬を服用中あるいは通院中の方、妊娠中の方は、お医者様にご相談の上お召し上がりください。 ●直射日光、高温多湿な場所をさけて保存してください。 ●お子様の手の届かないところで保管してください。 ●開封後はしっかり開封口を閉め、なるべく早くお召し上がりください。 食生活は、主食、主菜、副菜を基本に、食事のバランスを。 レビュー 関連する商品 キャンペーン 送料無料 【父の日限定】アスタキサンチン 30日分 3個セット 4,617 円 3,915 円（税込） 15%off 6月21日まで カートに入れる キャンペーン ネコポス コンビニ受取 亜鉛 30日分 3個セット 810 円 783 円（税込） 3%off 6月2日まで カートに入れる キャンペーン 送料無料 ネコポス コンビニ受取 醗酵黒セサミン プレミアム 30日分 2個セット 5,940 円 5,697 円（税込） 4%off 6月25日まで カートに入れる キャンペーン 送料無料 【父の日限定】香酢（こうず） 30日分 4個セット 4,752 円 3,888 円（税込） 18%off 6月21日まで カートに入れる 関連カテゴリ 健康食品・サプリメント 健康食品・サプリメント 目的で探す 元気・スタミナ カートに追加しました この商品はすでにお気に入りリストに追加されています。 新作アイテム今すぐチェック --> 新作アイテム 今すぐチェック 新作アイテム今すぐチェック --> お買い得商品を お見逃しなく！ 新作アイテム今すぐチェック --> 最大25％OFF 業界最大級の割引率 新作アイテム今すぐチェック --> オンラインショップ 限定品 新作アイテム今すぐチェック --> 安全性を第一に考えた 製品づくり 新作アイテム今すぐチェック --> 読み物や特集ページは コチラ お得な購入特典 すべて見る 最大10%OFF！ 一括購入割引 税込3,780円以上のご購入で、 当社が送料を負担いたします。 代金引換払い 手数料無料 ネットポイント 5%還元 化粧品ラ","productId":"32535","validation":{"status":"failed","reasons":["no_canonical_match","no_dosed_facts"],"summary":"No usable per-serving product facts.","checkedAt":"2026-05-21T10:14:17.326Z","matchableFactCount":0},"description":"生きた酵素をそのまま！ 穀物9種を麹菌3種で醗酵させた“穀物麹”サプリ","importScope":"dhc_japan_supplements","priceAmou